1	const BASE_PREMIUMS: Record<string, number> = {
2	  sword: 100,
3	  amulet: 60,
4	  staff: 80,
5	  potion: 40,
6	  rune: 25,
7	};
8	
9	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
10	const PROCESSING_FEE = 5;
11	const COMPONENT_TYPES = new Set(["rune"]);
12	const COMPONENT_BLOCK_SIZE = 3;
13	const COMPONENT_BLOCK_BASE = 60;
14	
15	const baseForType = (type: string, count: number): number => {
16	  if (COMPONENT_TYPES.has(type)) {
17	    const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
18	    const remainder = count % COMPONENT_BLOCK_SIZE;
19	    return blocks * COMPONENT_BLOCK_BASE + remainder * BASE_PREMIUMS[type];
20	  }
21	  return count * BASE_PREMIUMS[type];
22	};
23	
24	export const runScenario = (scenario: any): unknown => {
25	  const items = scenario.steps[0].items;
26	  const countsByType = new Map<string, number>();
27	  for (const item of items) {
28	    countsByType.set(item.type, (countsByType.get(item.type) ?? 0) + 1);
29	  }
30	  let itemsBase = 0;
31	  for (const [type, count] of countsByType) {
32	    itemsBase += baseForType(type, count);
33	  }
34	  const itemsTotal = itemsBase + itemsBase * FIRST_INSURANCE_SURCHARGE_RATE;
35	  const premium = Math.ceil(itemsTotal + PROCESSING_FEE);
36	  return { results: [{ premium }] };
37	};
